 39→class EditorJetpackSocialViewModel @Inject constructor(
 40→    private val dispatcher: Dispatcher,
 41→    private val accountStore: AccountStore,
 42→    private val getPublicizeConnectionsForUserUseCase: GetPublicizeConnectionsForUserUseCase,
 43→    private val getJetpackSocialShareMessageUseCase: GetJetpackSocialShareMessageUseCase,
 44→    private val getJetpackSocialShareLimitStatusUseCase: GetJetpackSocialShareLimitStatusUseCase,
 45→    private val jetpackUiStateMapper: EditPostPublishSettingsJetpackSocialUiStateMapper,
 46→    private val postSocialSharingModelMapper: PostSocialSharingModelMapper,
 47→    private val publicizeTableWrapper: PublicizeTableWrapper,
 48→    private val appPrefsWrapper: AppPrefsWrapper,
 49→    private val siteStore: SiteStore,
 50→    private val jetpackSocialSharingTracker: JetpackSocialSharingTracker,
 51→    @Named(BG_THREAD) private val bgDispatcher: CoroutineDispatcher,
 52→) : ScopedViewModel(bgDispatcher) {
 53→    private lateinit var siteModel: SiteModel
 54→    private lateinit var editPostRepository: EditPostRepository
 55→
 56→    private val _jetpackSocialContainerVisibility = MutableLiveData<JetpackSocialContainerVisibility>()
 57→    val jetpackSocialContainerVisibility: LiveData<JetpackSocialContainerVisibility> = _jetpackSocialContainerVisibility
 58→
 59→    private val _jetpackSocialUiState = MutableLiveData<JetpackSocialUiState>()
 60→    val jetpackSocialUiState: LiveData<JetpackSocialUiState> = _jetpackSocialUiState
 61→
 62→    // this is a SingleLiveEvent so it should have one, and only one, observer (the Activity)
 63→    private val _actionEvents = SingleLiveEvent<ActionEvent>()
 64→    val actionEvents: LiveData<ActionEvent> = _actionEvents
 65→
 66→    private var jetpackSocialShareMessage = ""
 67→    private lateinit var shareLimit: ShareLimit
 68→    private val connections = mutableListOf<PostSocialConnection>()
 69→
 70→    var isStarted: Boolean = false
 71→
 72→    private var isLastActionOnResumeHandled = false
 73→
 74→    private val currentPost: PostImmutableModel?
 75→        get() = editPostRepository.getPost()
 76→
 77→    fun start(siteModel: SiteModel, editPostRepository: EditPostRepository) {
 78→        if (isStarted) return
 79→
 80→        dispatcher.register(this)
 81→
 82→        isStarted = true
 83→        this.siteModel = siteModel
 84→        this.editPostRepository = editPostRepository
 85→
 86→        startJetpackSocial()
 87→    }
 88→
 89→    private fun startJetpackSocial() {
 90→        if (shouldShowJetpackSocial()) {
 91→            launch {
 92→                shareLimit = getJetpackSocialShareLimitStatusUseCase.execute(siteModel)
 93→                loadConnections()
 94→                loadJetpackSocialIfSupported()
 95→            }
 96→        } else {
 97→            _jetpackSocialContainerVisibility.value = JetpackSocialContainerVisibility.ALL_HIDDEN
 98→        }
 99→    }
100→
101→    fun onResume(jetpackSocialFlow: JetpackSocialFlow) {
102→        _jetpackSocialUiState.value?.let { uiState ->
103→            if (uiState is JetpackSocialUiState.Loaded && uiState.showShareLimitUi) {
104→                jetpackSocialSharingTracker.trackShareLimitDisplayed(jetpackSocialFlow)
105→            } else if (uiState is JetpackSocialUiState.NoConnections) {
106→                trackAddConnectionCtaDisplayedIfVisible(jetpackSocialFlow)
107→            }
108→        }
109→        if (!isLastActionOnResumeHandled) {
110→            isLastActionOnResumeHandled = true
111→            when (actionEvents.value) {
112→                is ActionEvent.OpenSocialConnectionsList -> {
113→                    // When getting back from publicize connections screen, we should update connections to
114→                    // make sure we have the latest data.
115→                    launch {
116→                        updateConnections()
117→                        loadJetpackSocialIfSupported()
118→                    }
119→                }
120→
121→                is ActionEvent.OpenSubscribeJetpackSocial -> {
122→                    // We have to update SiteModel to make sure we have the latest data regarding user hired plans
123→                    dispatcher.dispatch(SiteActionBuilder.newFetchSiteAction(siteModel))
124→                }
125→
126→                else -> {
127→                    // Do nothing
128→                }
129→            }
130→        }
131→    }
132→
133→    private suspend fun loadConnections() {
134→        val publicizeConnections = getPublicizeConnectionsForUserUseCase.execute(
135→            siteId = siteModel.siteId,
136→            userId = accountStore.account.userId
137→        )
138→        connections.clear()
139→        connections.addAll(publicizeConnections.map { connection ->
140→            PostSocialConnection.fromPublicizeConnection(connection, false)
141→        })
142→        updateInitialConnectionListSharingStatus()
143→    }
144→
145→    private suspend fun updateConnections() {
146→        val publicizeConnections = getPublicizeConnectionsForUserUseCase.execute(
147→            siteId = siteModel.siteId,
148→            userId = accountStore.account.userId,
149→            shouldForceUpdate = false,
150→        )
151→        // Update connections list with new connections
152→        val currentConnectionIds = connections.map { it.connectionId }
153→        publicizeConnections.forEach { publicizeConnection ->
154→            if (currentConnectionIds.doesNotContain(publicizeConnection.connectionId)) {
155→                connections.add(PostSocialConnection.fromPublicizeConnection(publicizeConnection, false))
156→            }
157→        }
158→        // Update connections list with removed connections
159→        currentConnectionIds.forEach { currentConnectionId ->
160→            if (publicizeConnections.map { connection -> connection.connectionId }
161→                    .doesNotContain(currentConnectionId)) {
162→                connections.removeAll { connection -> connection.connectionId == currentConnectionId }
163→            }
164→        }
165→    }
166→
167→    private suspend fun loadJetpackSocialIfSupported() {
168→        if (!shouldShowJetpackSocial()) {
169→            _jetpackSocialContainerVisibility.postValue(JetpackSocialContainerVisibility.ALL_HIDDEN)
170→            return
171→        }
172→
173→        if (showNoConnections()) {
174→            // If user previously dismissed the no connections container by tapping the "Not now" button,
175→            // we should hide the container.
176→            _jetpackSocialContainerVisibility.postValue(getJetpackSocialContainerVisibilityFromPrefs())
177→
178→            _jetpackSocialUiState.postValue(
179→                jetpackUiStateMapper.mapNoConnections(
180→                    ::onJetpackSocialConnectProfilesClick,
181→                    ::onJetpackSocialNotNowClick
182→                )
183→            )
184→        } else {
185→            _jetpackSocialContainerVisibility.postValue(JetpackSocialContainerVisibility.ALL_VISIBLE)
186→            _jetpackSocialUiState.postValue(mapLoaded())
187→        }
188→    }
189→
190→    private fun shouldShowJetpackSocial() = !editPostRepository.isPage
191→            && siteModel.supportsPublicize()
192→            && currentPost?.status != PostStatus.PRIVATE.toString()
193→
194→    private suspend fun mapLoaded(): JetpackSocialUiState.Loaded {
195→        val shareMessage = jetpackSocialShareMessage.ifEmpty {
196→            getJetpackSocialShareMessageUseCase.execute(currentPost?.id ?: -1)
197→        }
198→        val socialSharingModel = postSocialSharingModelMapper.map(connections, shareLimit)
199→        return jetpackUiStateMapper.mapLoaded(
200→            connections = connections,
201→            shareLimit = shareLimit,
202→            socialSharingModel = socialSharingModel,
203→            onSubscribeClick = ::onJetpackSocialSubscribeClick,
204→            shareMessage = shareMessage,
205→            onShareMessageClick = ::onJetpackSocialMessageClick,
206→            onConnectionClick = ::onJetpackSocialConnectionClick,
207→            isPostPublished = isPostPublished(),
208→        )
209→    }
210→
211→    private fun showNoConnections(): Boolean =
212→        connections.isEmpty()
213→                && publicizeTableWrapper.getServiceList().any { it.status != PublicizeService.Status.UNSUPPORTED }
214→
215→    private fun updateInitialConnectionListSharingStatus() {
216→        if (isPostPublished()) {
217→            connections.map { it.isSharingEnabled = false }
218→            return
219→        }
220→        val shareLimitValue = shareLimit
221→        val skipConnections = postPublicizeSkipConnections()
222→        if (shareLimitValue is ShareLimit.Enabled) {
223→            // If shares remaining < number of connections, all connections are unchecked by default
224→            updateInitialConnectionListShareLimitEnabled(shareLimitValue, skipConnections)
225→        } else {
226→            updateInitialConnectionListShareLimitDisabled(skipConnections)
227→        }
228→    }
229→
230→    private fun updateInitialConnectionListShareLimitEnabled(
231→        shareLimitValue: ShareLimit.Enabled,
232→        skipConnections: List<PublicizeSkipConnection>
233→    ) {
234→        if (shareLimitValue.sharesRemaining < connections.size) {
235→            connections.map { it.isSharingEnabled = false }
236→        } else {
237→            connections.take(shareLimitValue.sharesRemaining).map {
238→                it.isSharingEnabled = true
239→            }
240→            connections.forEach { connection ->
241→                // Use metadata to verify if this connection was previously disabled by the user
242→                skipConnections.firstOrNull { it.connectionId() == connection.connectionId.toString() }
243→                    ?.let { connection.isSharingEnabled = it.isConnectionEnabled() }
244→            }
245→        }
246→    }
247→
248→    private fun updateInitialConnectionListShareLimitDisabled(skipConnections: List<PublicizeSkipConnection>) {
249→        // With share limit disabled we can enable all connections but still considering the skip
250→        // connections metadata
251→        connections.map { it.isSharingEnabled = true }
252→        connections.forEach { connection ->
253→            // Use metadata to verify if this connection was previously disabled by the user
254→            skipConnections.firstOrNull { it.connectionId() == connection.connectionId.toString() }
255→                ?.let { connection.isSharingEnabled = it.isConnectionEnabled() }
256→        }
257→    }
258→
259→    private fun getJetpackSocialContainerVisibilityFromPrefs(): JetpackSocialContainerVisibility {
260→        return JetpackSocialContainerVisibility(
261→            showInPrepublishingSheet = appPrefsWrapper.getShouldShowJetpackSocialNoConnections(
262→                siteModel.siteId,
263→                JetpackSocialFlow.PRE_PUBLISHING
264→            ),
265→            showInPostSettings = appPrefsWrapper.getShouldShowJetpackSocialNoConnections(
266→                siteModel.siteId,
267→                JetpackSocialFlow.POST_SETTINGS
268→            )
269→        )
270→    }
271→
272→    private fun postPublicizeSkipConnections(): List<PublicizeSkipConnection> =
273→        currentPost?.publicizeSkipConnectionsList ?: emptyList()
274→
275→    private fun isPostPublished(): Boolean =
276→        currentPost?.status?.let { status ->
277→            status == PostStatus.PUBLISHED.toString()
278→        } ?: false
279→
280→    @VisibleForTesting
281→    fun onJetpackSocialConnectProfilesClick(jetpackSocialFlow: JetpackSocialFlow) {
282→        isLastActionOnResumeHandled = false
283→        jetpackSocialSharingTracker.trackAddConnectionTapped(jetpackSocialFlow)
284→        _actionEvents.value = ActionEvent.OpenSocialConnectionsList(siteModel = siteModel)
285→    }
286→
287→    @VisibleForTesting
288→    fun onJetpackSocialNotNowClick(jetpackSocialFlow: JetpackSocialFlow) {
289→        appPrefsWrapper.setShouldShowJetpackSocialNoConnections(false, siteModel.siteId, jetpackSocialFlow)
290→        jetpackSocialSharingTracker.trackAddConnectionDismissCtaTapped(jetpackSocialFlow)
291→        _jetpackSocialContainerVisibility.value = getJetpackSocialContainerVisibilityFromPrefs()
292→    }
293→
294→    @VisibleForTesting
295→    fun onJetpackSocialConnectionClick(
296→        connection: PostSocialConnection,
297→        enabled: Boolean,
298→        jetpackSocialFlow: JetpackSocialFlow
299→    ) {
300→        jetpackSocialSharingTracker.trackConnectionToggled(jetpackSocialFlow, enabled)
301→        launch {
302→            // Update UI
303→            connections.firstOrNull { it.connectionId == connection.connectionId }?.let {
304→                it.isSharingEnabled = enabled
305→            }
306→            _jetpackSocialUiState.postValue(mapLoaded())
307→            // Update local post
308→            editPostRepository.updateAsync({ postModel ->
309→                val connectionId = connection.connectionId.toString()
310→                with(postModel.publicizeSkipConnectionsList.toMutableList()) {
311→                    firstOrNull { it.connectionId() == connectionId }?.updateValue(enabled)
312→                        ?: run {
313→                            // Connection wasn't part of skip connections before, so we must add it
314→                            // with the correct value
315→                            add(PublicizeSkipConnection.createNew(connectionId, enabled))
316→                        }
317→                    postModel.updatePublicizeSkipConnections(this)
318→                }
319→                true
320→            })
321→        }
322→    }
323→
324→    private fun onJetpackSocialMessageClick() {
325→        val shareMessage = with(_jetpackSocialUiState.value) {
326→            if (this is JetpackSocialUiState.Loaded) {
327→                shareMessage
328→            } else ""
329→        }
330→        _actionEvents.value = ActionEvent.OpenEditShareMessage(shareMessage)
331→    }
332→
333→    @VisibleForTesting
334→    fun onJetpackSocialSubscribeClick(jetpackSocialFlow: JetpackSocialFlow) {
335→        isLastActionOnResumeHandled = false
336→        jetpackSocialSharingTracker.trackUpgradeLinkTapped(jetpackSocialFlow)
337→        _actionEvents.value = ActionEvent.OpenSubscribeJetpackSocial(
338→            siteModel = siteModel,
339→            url = HIRE_JETPACK_SOCIAL_BASIC_URL.format(
340→                siteModel.url.replace(Regex("^(https?://)", RegexOption.IGNORE_CASE), "")
341→            ),
342→        )
343→    }
344→
345→    fun onJetpackSocialShareMessageChanged(newShareMessage: String?) {
346→        val currentState = _jetpackSocialUiState.value
347→        if (newShareMessage != null && currentState is JetpackSocialUiState.Loaded) {
348→            val shareMessage = newShareMessage.ifEmpty { currentPost?.title ?: "" }
349→            editPostRepository.updateAsync({ postModel ->
350→                postModel.setAutoShareMessage(shareMessage)
351→                true
352→            })
353→            _jetpackSocialUiState.value = currentState.copy(shareMessage = shareMessage)
354→            jetpackSocialShareMessage = shareMessage
355→        }
356→    }
357→
358→    override fun onCleared() {
359→        dispatcher.unregister(this)
360→        super.onCleared()
361→    }
362→
363→    @Subscribe(threadMode = ThreadMode.MAIN)
364→    fun onSiteChanged(event: OnSiteChanged) {
365→        if (event.isError) {
366→            return
367→        }
368→        launch {
369→            val updatedSite = siteStore.getSiteByLocalId(siteModel.id)
370→            if (updatedSite != null) {
371→                siteModel = updatedSite
372→                shareLimit = getJetpackSocialShareLimitStatusUseCase.execute(siteModel)
373→                loadJetpackSocialIfSupported()
374→            }
375→        }
376→    }
377→
378→    private fun trackAddConnectionCtaDisplayedIfVisible(jetpackSocialFlow: JetpackSocialFlow) {
379→        val trackEvent = when (jetpackSocialFlow) {
380→            JetpackSocialFlow.PRE_PUBLISHING ->
381→                jetpackSocialContainerVisibility.value?.showInPrepublishingSheet == true
382→            JetpackSocialFlow.POST_SETTINGS ->
383→                _jetpackSocialContainerVisibility.value?.showInPostSettings == true
384→            else -> false
385→        }
386→
387→        if (trackEvent) jetpackSocialSharingTracker.trackAddConnectionCtaDisplayed(jetpackSocialFlow)
388→    }
389→
390→    fun onPostStatusChanged() {
391→        startJetpackSocial()
392→    }
393→
394→    data class JetpackSocialContainerVisibility(
395→        val showInPrepublishingSheet: Boolean,
396→        val showInPostSettings: Boolean,
397→    ) {
398→        companion object {
399→            @VisibleForTesting
400→            val ALL_HIDDEN = JetpackSocialContainerVisibility(
401→                showInPrepublishingSheet = false,
402→                showInPostSettings = false,
403→            )
404→
405→            @VisibleForTesting
406→            val ALL_VISIBLE = JetpackSocialContainerVisibility(
407→                showInPrepublishingSheet = true,
408→                showInPostSettings = true,
409→            )
410→        }
411→    }
412→
413→    sealed class JetpackSocialUiState {
414→        object Loading : JetpackSocialUiState()
415→
416→        data class Loaded(
417→            val jetpackSocialConnectionDataList: List<JetpackSocialConnectionData>,
418→            val socialSharingModel: PostSocialSharingModel,
419→            val showShareLimitUi: Boolean,
420→            val isShareMessageEnabled: Boolean,
421→            val shareMessage: String,
422→            val onShareMessageClick: () -> Unit,
423→            val subscribeButtonLabel: String,
424→            val onSubscribeClick: (JetpackSocialFlow) -> Unit,
425→        ) : JetpackSocialUiState()
426→
427→        data class NoConnections(
428→            val trainOfIconsModels: List<TrainOfIconsModel>,
429→            val message: String,
430→            val connectProfilesButtonLabel: String,
431→            val onConnectProfilesClick: (JetpackSocialFlow) -> Unit,
432→            val notNowButtonLabel: String,
433→            val onNotNowClick: (JetpackSocialFlow) -> Unit,
434→        ) : JetpackSocialUiState()
435→    }
436→
437→    sealed class ActionEvent {
438→        data class OpenEditShareMessage(val shareMessage: String) : ActionEvent()
439→
440→        data class OpenSocialConnectionsList(val siteModel: SiteModel) : ActionEvent()
441→
442→        data class OpenSubscribeJetpackSocial(
443→            val siteModel: SiteModel,
444→            val url: String,
445→        ) : ActionEvent()
446→    }
447→
448→    companion object {
449→        @VisibleForTesting
450→        const val HIRE_JETPACK_SOCIAL_BASIC_URL =
451→            "https://wordpress.com/checkout/%s/jetpack_social_basic_yearly"
452→    }
453→}
