17→class EditPostSettingsJetpackSocialContainerView @JvmOverloads constructor(
18→    context: Context,
19→    attrs: AttributeSet? = null
20→) : AbstractComposeView(context, attrs) {
21→    private val uiState: MutableState<JetpackSocialUiState> = mutableStateOf(Loading)
22→    var jetpackSocialUiState: JetpackSocialUiState
23→        get() = uiState.value
24→        set(value) {
25→            if (uiState.value != value) uiState.value = value
26→        }
27→
28→    @Composable
29→    override fun Content() {
30→        AppThemeEditor {
31→            with(uiState.value) {
32→                when (this) {
33→                    is Loading -> {
34→                        // no-op
35→                    }
36→
37→                    is Loaded -> {
38→                        Column {
39→                            EditPostJetpackSocialConnectionsContainer(
40→                                jetpackSocialConnectionDataList = jetpackSocialConnectionDataList,
41→                                jetpackSocialFlow = JetpackSocialFlow.POST_SETTINGS,
42→                                shareMessage = shareMessage,
43→                                isShareMessageEnabled = isShareMessageEnabled,
44→                                onShareMessageClick = onShareMessageClick,
45→                            )
46→                            if (showShareLimitUi) {
47→                                EditPostSettingsJetpackSocialSharesContainer(
48→                                    postSocialSharingModel = socialSharingModel,
49→                                    subscribeButtonLabel = subscribeButtonLabel,
50→                                    onSubscribeClick = { onSubscribeClick(JetpackSocialFlow.POST_SETTINGS) },
51→                                )
52→                            }
53→                        }
54→                    }
55→
56→                    is NoConnections -> {
57→                        EditPostSettingsJetpackSocialNoConnections(
58→                            trainOfIconsModels = trainOfIconsModels,
59→                            message = message,
60→                            connectProfilesButtonLabel = connectProfilesButtonLabel,
61→                            onConnectProfilesCLick = { onConnectProfilesClick(JetpackSocialFlow.POST_SETTINGS) },
62→                            notNowButtonLabel = notNowButtonLabel,
63→                            onNotNowClick = { onNotNowClick(JetpackSocialFlow.POST_SETTINGS) },
64→                        )
65→                    }
66→                }
67→            }
68→        }
69→    }
70→}
