 41→    public static final String WP_LOOM_EMBED_JETPACK_VERSION = "9.0";
 42→    public static final String WP_SMARTFRAME_EMBED_JETPACK_VERSION = "10.2";
 43→    private static final int GB_ROLLOUT_PERCENTAGE_PHASE_1 = 100;
