 45→
 46→    /**
 47→     * Migrate the old app-wide editor preference value to per-site setting. wpcom sites will make a network call
 48→     * and store the value on the backend. selfHosted sites just store the value in the local DB in FluxC
 49→     * <p>
 50→     * Strategy: Check if there is the old app-wide preference still available (v12.9 and before used it).
 51→     * -- 12.9 ON -> turn all sites ON in 13.0
 52→     * -- 12.9 OPTED OUT (were auto-opted in but turned it OFF) -> turn all sites OFF in 13.0
 53→     */
 54→    public static void migrateAppWideMobileEditorPreferenceToRemote(final AccountStore accountStore,
 55→                                                                    final SiteStore siteStore,
 56→                                                                    final Dispatcher dispatcher) {
 57→        // Skip if the user is not signed in
 58→        if (!FluxCUtils.isSignedInWPComOrHasWPOrgSite(accountStore, siteStore)) {
 59→            return;
 60→        }
 61→
 62→        // If the user is already in the rollout group, we can skip this the migration.
 63→        if (AppPrefs.isUserInGutenbergRolloutGroup()) {
 64→            return;
 65→        }
 66→
 67→        // -------- Rollout: Phase 2 -------
 68→        //
 69→        // If user has any Aztec enabled sites, we'll migrate their sites to Gutenberg and schedule showing popup.
 70→        if (atLeastOneSiteHasAztecEnabled(siteStore)) {
 71→            // Randomly pick the user in the rollout group
 72→            if (accountStore.getAccount().getUserId() % 100 >= (100 - GB_ROLLOUT_PERCENTAGE_PHASE_2)) {
 73→                if (!NetworkUtils.isNetworkAvailable(WordPress.getContext())) {
 74→                    // If the network is not available, abort. We can't update the remote setting.
 75→                    return;
 76→                }
 77→
 78→                for (SiteModel site : siteStore.getSites()) {
 79→                    // Show "phase 2" dialog on sites that get switched from aztec to gutenberg
 80→                    if (TextUtils.equals(site.getMobileEditor(), AZTEC_EDITOR_NAME)) {
 81→                        AppPrefs.setShowGutenbergInfoPopupPhase2ForNewPosts(site.getUrl(), true);
 82→                        // Will show the popup again, even if it was displayed in the past
 83→                        AppPrefs.setGutenbergInfoPopupDisplayed(site.getUrl(), false);
 84→                        continue;
 85→                    }
 86→
 87→                    // Show "phase 1" dialog on sites that get switched from "empty" (no pref) to gutenberg
 88→                    if (TextUtils.isEmpty(site.getMobileEditor())) {
 89→                        AppPrefs.setShowGutenbergInfoPopupForTheNewPosts(site.getUrl(), true);
 90→                    }
 91→                }
 92→
 93→                // Track and enable Gutenberg for all sites using a single network call. Ideally we would track this
 94→                // on the network response, but this would make this rollout even more complex.
 95→                // There might be some rare events when we register a site switched to Gutenberg which is actually
 96→                // still on Aztec.
 97→                trackGutenbergEnabledForNonGutenbergSites(siteStore,
 98→                        BlockEditorEnabledSource.ON_PROGRESSIVE_ROLLOUT_PHASE_2);
 99→                dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorForAllSitesAction(
100→                        new DesignateMobileEditorForAllSitesPayload(SiteUtils.GB_EDITOR_NAME, false)));
101→
102→                // After enabling Gutenberg on these sites, we consider the user entered the rollout group
103→                AppPrefs.setUserInGutenbergRolloutGroup();
104→            }
105→        }
106→
107→        // -------- Rollout: Phase 1 -------
108→        //
109→        // Check if the user has been "randomly" selected to enter the rollout group.
110→        //
111→        // For self hosted sites, there are often one or two users, and the user id is probably 0, 1 in these cases.
112→        // If we exclude low ids, we won't get an not an homogeneous distribution over self hosted and WordPress.com
113→        // users, but the purpose of this is to do a progressive rollout, not an necessarily an homogeneous rollout.
114→        //
115→        // To exclude ids 0 and 1, to rollout for 10% users,
116→        // we'll use a test like `id % 100 >= 90` instead of `id % 100 < 10`.
117→        if (accountStore.getAccount().getUserId() % 100 >= (100 - GB_ROLLOUT_PERCENTAGE_PHASE_1)) {
118→            if (atLeastOneSiteHasAztecEnabled(siteStore)) {
119→                // If the user has opt-ed out from at least one of their site, then exclude them from the cohort
120→                return;
121→            }
122→
123→            if (!NetworkUtils.isNetworkAvailable(WordPress.getContext())) {
124→                // If the network is not available, abort. We can't update the remote setting.
125→                return;
126→            }
127→
128→            // Force the dialog to be shown on updated sites
129→            for (SiteModel site : siteStore.getSites()) {
130→                if (TextUtils.isEmpty(site.getMobileEditor())) {
131→                    AppPrefs.setShowGutenbergInfoPopupForTheNewPosts(site.getUrl(), true);
132→                }
133→            }
134→
135→            // Track and enable and  Gutenberg for all sites using a single network call. Ideally we would track this
136→            // on the network response, but this would make this rollout even more complex.
137→            // There might be some rare events when we register a site switched to Gutenberg which is actually
138→            // still on Aztec.
139→            trackGutenbergEnabledForNonGutenbergSites(siteStore,
140→                    BlockEditorEnabledSource.ON_PROGRESSIVE_ROLLOUT_PHASE_1);
141→            dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorForAllSitesAction(
142→                    new DesignateMobileEditorForAllSitesPayload(SiteUtils.GB_EDITOR_NAME)));
143→
144→            // After enabling Gutenberg on these sites, we consider the user entered the rollout group
145→            AppPrefs.setUserInGutenbergRolloutGroup();
146→        }
147→
148→        if (!AppPrefs.isDefaultAppWideEditorPreferenceSet()) {
149→            return;
150→        }
151→        final boolean oldAppWidePreferenceValue = AppPrefs.isGutenbergDefaultForNewPosts();
152→
153→        if (oldAppWidePreferenceValue) {
154→            dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorForAllSitesAction(
155→                    new DesignateMobileEditorForAllSitesPayload(SiteUtils.GB_EDITOR_NAME)));
156→        } else {
157→            dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorForAllSitesAction(
158→                    new DesignateMobileEditorForAllSitesPayload(SiteUtils.AZTEC_EDITOR_NAME)));
159→        }
160→    }
