167→    private suspend fun loadJetpackSocialIfSupported() {
168→        if (!shouldShowJetpackSocial()) {
169→            _jetpackSocialContainerVisibility.postValue(JetpackSocialContainerVisibility.ALL_HIDDEN)
170→            return
171→        }
172→
173→        if (showNoConnections()) {
174→            // If user previously dismissed the no connections container by tapping the "Not now" button,
175→            // we should hide the container.
176→            _jetpackSocialContainerVisibility.postValue(getJetpackSocialContainerVisibilityFromPrefs())
177→
178→            _jetpackSocialUiState.postValue(
179→                jetpackUiStateMapper.mapNoConnections(
180→                    ::onJetpackSocialConnectProfilesClick,
181→                    ::onJetpackSocialNotNowClick
182→                )
183→            )
184→        } else {
185→            _jetpackSocialContainerVisibility.postValue(JetpackSocialContainerVisibility.ALL_VISIBLE)
186→            _jetpackSocialUiState.postValue(mapLoaded())
187→        }
188→    }
