190→    private fun shouldShowJetpackSocial() = !editPostRepository.isPage
191→            && siteModel.supportsPublicize()
192→            && currentPost?.status != PostStatus.PRIVATE.toString()
193→
194→    private suspend fun mapLoaded(): JetpackSocialUiState.Loaded {
195→        val shareMessage = jetpackSocialShareMessage.ifEmpty {
196→            getJetpackSocialShareMessageUseCase.execute(currentPost?.id ?: -1)
197→        }
198→        val socialSharingModel = postSocialSharingModelMapper.map(connections, shareLimit)
199→        return jetpackUiStateMapper.mapLoaded(
200→            connections = connections,
201→            shareLimit = shareLimit,
202→            socialSharingModel = socialSharingModel,
203→            onSubscribeClick = ::onJetpackSocialSubscribeClick,
204→            shareMessage = shareMessage,
205→            onShareMessageClick = ::onJetpackSocialMessageClick,
206→            onConnectionClick = ::onJetpackSocialConnectionClick,
207→            isPostPublished = isPostPublished(),
208→        )
209→    }
210→
211→    private fun showNoConnections(): Boolean =
212→        connections.isEmpty()
213→                && publicizeTableWrapper.getServiceList().any { it.status != PublicizeService.Status.UNSUPPORTED }
214→
215→    private fun updateInitialConnectionListSharingStatus() {
216→        if (isPostPublished()) {
217→            connections.map { it.isSharingEnabled = false }
218→            return
219→        }
220→        val shareLimitValue = shareLimit
221→        val skipConnections = postPublicizeSkipConnections()
222→        if (shareLimitValue is ShareLimit.Enabled) {
223→            // If shares remaining < number of connections, all connections are unchecked by default
224→            updateInitialConnectionListShareLimitEnabled(shareLimitValue, skipConnections)
225→        } else {
226→            updateInitialConnectionListShareLimitDisabled(skipConnections)
227→        }
228→    }
229→
230→    private fun updateInitialConnectionListShareLimitEnabled(
231→        shareLimitValue: ShareLimit.Enabled,
232→        skipConnections: List<PublicizeSkipConnection>
233→    ) {
234→        if (shareLimitValue.sharesRemaining < connections.size) {
235→            connections.map { it.isSharingEnabled = false }
236→        } else {
237→            connections.take(shareLimitValue.sharesRemaining).map {
238→                it.isSharingEnabled = true
