309→    /**
310→     * Checks if site Jetpack version is higher than limit version
311→     *
312→     * @param site
313→     * @param limitVersion minimal acceptable Jetpack version
314→     * @return
315→     */
316→    public static boolean checkMinimalJetpackVersion(SiteModel site, String limitVersion) {
317→        String jetpackVersion = site.getJetpackVersion();
318→        if (site.isUsingWpComRestApi() && site.isJetpackConnected() && !TextUtils.isEmpty(jetpackVersion)) {
319→            // Jetpack version field is sometimes "false" instead of a number on self-hosted sites that are no
320→            // longer active.
321→            if (jetpackVersion.equals("false")) {
322→                return false;
323→            }
324→            return VersionUtils.checkMinimalVersion(jetpackVersion, limitVersion);
325→        }
326→        return false;
327→    }
